#include <iostream>#include <vector>#include <algorithm>#include <cmath>#include <string>#include <map>#include <set>#include <iomanip>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll n;    cin >> n;        vll a(n);    for(int i=0; i<n; i++) cin >> a[i];    int cnt=0;    bool btw_zero=false;    for(int i=0;i<n;i++){        if(a[i]==0){            cnt++;        }        }    int left=0, right=n-1;    while(left<n && a[left]==0) left++;    while(right>=0 && a[right]==0) right--;    for(int i=left;i<=right;i++){        if(a[i]==0){            btw_zero=true;            break;        }    }    if(cnt==n){        cout << "0\n";    }    else if(btw_zero==false){        cout << "1\n";    }    else if(btw_zero){        cout << "2\n";    }                    } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}